   private static Map<String, List<String>> questionBank = new HashMap();
   public static List<String> englishQuestions = new ArrayList();
   public static List<String> bahasaQuestions = new ArrayList();

   public static List<String> chooseRandomQuestions(int itemsToSelect) {
      return chooseRandomQuestions(TriviaQuestionCategoryEnum.ENGLISH, itemsToSelect);
   }

   public static List<String> chooseRandomQuestions(TriviaQuestionCategoryEnum category, int itemsToSelect) {
      Random random = new Random();
      List<String> questions = getQuestionSet(category);
      int sourceSize = questions.size();
      int[] selections = new int[itemsToSelect];
      ArrayList<String> resultArray = new ArrayList();

      for(int count = 0; count < itemsToSelect; ++count) {
         int selection = random.nextInt(sourceSize - count);
         selections[count] = selection;

         for(int scanIdx = count - 1; scanIdx >= 0; --scanIdx) {
            if (selection >= selections[scanIdx]) {
               ++selection;
            }
         }

         resultArray.add(questions.get(selection));
      }

      return resultArray;
   }

   private static List<String> getQuestionSet(TriviaQuestionCategoryEnum category) {
      switch(category.value()) {
      case 1:
         return englishQuestions;
      case 2:
         return bahasaQuestions;
      default:
         return englishQuestions;
      }
   }

   public static void main(String[] args) {
      List<String> questionList = chooseRandomQuestions(TriviaQuestionCategoryEnum.ENGLISH, 10);
      int questionNumber = 0;
      Iterator i$ = questionList.iterator();

      while(i$.hasNext()) {
         String questionObj = (String)i$.next();
         System.out.println(questionObj);

         Question question;
         for(StringTokenizer tokenizer = new StringTokenizer(questionObj, "\t"); tokenizer.hasMoreTokens(); System.out.println(question)) {
            TriviaQuestionTypeEnum typeEnum = null;
            String questionTypeStr = tokenizer.nextToken();
            boolean var8 = true;

            try {
               int type = Integer.parseInt(questionTypeStr);
               typeEnum = TriviaQuestionTypeEnum.fromValue(type);
            } catch (Exception var13) {
               System.out.println("Error parsing question string: " + questionObj);
               typeEnum = TriviaQuestionTypeEnum.OPEN;
            }

            String questionStr = tokenizer.nextToken();
            String answer = tokenizer.nextToken();
            question = new Question(questionNumber++, typeEnum, questionStr, answer);
            if (typeEnum == TriviaQuestionTypeEnum.MULTIPLE_CHOICE && tokenizer.hasMoreTokens()) {
               char answerChar = tokenizer.nextToken().charAt(0);
               question.setAnswerChar(answerChar);
               System.out.println("ANSWER: " + answerChar);
            } else {
               System.out.println("Improper question format for a multiple choice question: " + questionObj);
            }
         }
      }

   }

